	client: Client,
	input: {
		config: ReturnType<typeof loadRhapsodyConfig>;
		updateProjectIssueStatus: typeof updateProjectIssueStatus;
		item: GitHubProjectIssueWorkItem;
		runId: string;
		attemptId: string;
