		decisions: input.existingDecisions ?? [],
		pullRequestNumber: input.pullRequestNumber,
		classification: checkSummary.classification,
		headSha: checkSummary.headSha,
	});

	if (freshDecision) {
		return {
			decisionId: freshDecision.id,
			workerRunId: null,
			classification: checkSummary.classification,
			skippedFreshDuplicate: true,
